package services

import javax.inject._
import play.api.db._
import slick.jdbc.JdbcProfile
import models._

class OrderService @Inject() (dbConfigProvider: DatabaseConfigProvider) {
  def getOrderDetails(id: Long): OrderDetails = {
    val dbConfig = dbConfigProvider.get[JdbcProfile]
    import dbConfig.driver.api._
    val orderTableQuery = TableQuery[Orders]
    val orderDetails = Await.result(orderTableQuery.filter(_.id === id).result, Duration.Inf)
    OrderDetails(orderDetails.name, orderDetails.price, orderDetails.quantity)
  }
}

